import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import Navbar from '../../components/common/Navbar';
import GlassCard from '../../components/common/GlassCard';
import { Calendar, Clock, DollarSign, Star, Camera } from 'lucide-react';

const SitterDashboard = () => {
    const { user } = useAuth();
    const [activeTab, setActiveTab] = useState('requests');
    const [requests, setRequests] = useState([]);
    const [earnings, setEarnings] = useState(0);

    // Availability state
    const days = ['LUN', 'MAR', 'MIE', 'JUE', 'VIE', 'SAB', 'DOM'];
    const times = ['manana', 'mediodia', 'tarde', 'noche'];
    const timeLabels = { manana: 'Mañana', mediodia: 'Medio Día', tarde: 'Tarde', noche: 'Noche' };

    const [availability, setAvailability] = useState(user?.availability || {
        LUN: { manana: false, mediodia: false, tarde: false, noche: false },
        MAR: { manana: false, mediodia: false, tarde: false, noche: false },
        MIE: { manana: false, mediodia: false, tarde: false, noche: false },
        JUE: { manana: false, mediodia: false, tarde: false, noche: false },
        VIE: { manana: false, mediodia: false, tarde: false, noche: false },
        SAB: { manana: false, mediodia: false, tarde: false, noche: false },
        DOM: { manana: false, mediodia: false, tarde: false, noche: false },
    });

    const [profileImage, setProfileImage] = useState(user?.avatar || null);

    const refreshData = () => {
        const reqs = JSON.parse(localStorage.getItem('booking_requests') || '[]');
        const myReqs = reqs.filter(r => r.sitterId === (user?.id || 1));
        setRequests(myReqs);

        // Calculate earnings (90% of completed jobs)
        const completed = myReqs.filter(r => r.status === 'COMPLETADO');
        const total = completed.reduce((acc, r) => acc + (r.total * 0.9), 0);
        setEarnings(total);
    };

    useEffect(() => {
        refreshData();
        window.addEventListener('storage', refreshData);
        return () => window.removeEventListener('storage', refreshData);
    }, [user]);

    const handleAction = (id, newStatus) => {
        const reqs = JSON.parse(localStorage.getItem('booking_requests') || '[]');
        const updated = reqs.map(r => r.id === id ? { ...r, status: newStatus } : r);
        localStorage.setItem('booking_requests', JSON.stringify(updated));
        refreshData();
        window.dispatchEvent(new Event('storage'));

        if (newStatus === 'ACEPTADA') alert("Solicitud aceptada.");
        if (newStatus === 'CONFIRMADO') alert("Pago verificado.");
    };

    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                const base64String = reader.result;
                setProfileImage(base64String);

                // Save to localStorage users
                const allUsers = JSON.parse(localStorage.getItem('users') || '[]');
                const updated = allUsers.map(u => u.id === user.id ? { ...u, avatar: base64String } : u);
                localStorage.setItem('users', JSON.stringify(updated));
                alert("Foto de perfil actualizada.");
            };
            reader.readAsDataURL(file);
        }
    };

    const toggleAvailability = (day, time) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], [time]: !prev[day][time] }
        }));
    };

    return (
        <div className="min-h-screen bg-background text-on-surface">
            <Navbar />
            <div className="container mx-auto px-4 pt-28 pb-12 flex flex-col md:flex-row gap-8">
                {/* Sidebar */}
                <aside className="w-full md:w-64 flex-shrink-0">
                    <GlassCard className="rounded-[32px] p-6 shadow-xl sticky top-28">
                        <div className="flex flex-col items-center mb-8">
                            <div className="relative group">
                                <div className="w-24 h-24 rounded-full bg-secondary-fixed flex items-center justify-center text-secondary text-3xl font-bold mb-4 overflow-hidden border-2 border-secondary">
                                    {profileImage ? (
                                        <img src={profileImage} alt="Profile" className="w-full h-full object-cover" />
                                    ) : (
                                        user?.full_name?.charAt(0) || 'C'
                                    )}
                                </div>
                                <label className="absolute bottom-4 right-0 bg-primary text-white p-1.5 rounded-full cursor-pointer shadow-lg hover:scale-110 transition-transform">
                                    <Camera size={16} />
                                    <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                                </label>
                            </div>
                            <h2 className="font-display-lg text-xl font-bold text-center">{user?.full_name}</h2>
                            <p className="text-on-surface-variant text-sm text-center">Cuidador Profesional</p>
                        </div>

                        <nav className="flex flex-col gap-2">
                            <button onClick={() => setActiveTab('requests')} className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'requests' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}><Calendar size={20} /> Solicitudes</button>
                            <button onClick={() => setActiveTab('earnings')} className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'earnings' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}><DollarSign size={20} /> Ganancias</button>
                            <button onClick={() => setActiveTab('profile')} className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'profile' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}><Star size={20} /> Editar Perfil</button>
                        </nav>
                    </GlassCard>
                </aside>

                {/* Main Content */}
                <main className="flex-1">
                    {activeTab === 'requests' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Solicitudes de Cuidado</h2>
                            <div className="space-y-4">
                                {requests.length > 0 ? requests.map(req => (
                                    <GlassCard key={req.id} className="rounded-[24px] p-6 shadow-md hover:shadow-lg transition-shadow">
                                        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                                            <div>
                                                <h3 className="font-display-lg text-xl font-bold mb-2">{req.parentName}</h3>
                                                <div className="flex gap-4 text-sm text-on-surface-variant">
                                                    <span className="flex items-center gap-1"><Calendar size={16}/> {req.date}</span>
                                                </div>
                                            </div>
                                            <div className="font-bold text-xl text-primary">${req.total}</div>
                                            <div className="flex gap-2 w-full md:w-auto">
                                                {req.status === 'PENDIENTE' && (
                                                    <>
                                                        <button onClick={() => handleAction(req.id, 'ACEPTADA')} className="flex-1 md:flex-none bg-primary text-white px-6 py-2 rounded-full font-bold hover:bg-primary-container transition">Aceptar</button>
                                                        <button onClick={() => handleAction(req.id, 'RECHAZADA')} className="flex-1 md:flex-none bg-error-container text-on-error-container px-6 py-2 rounded-full font-bold transition hover:bg-error hover:text-white">Rechazar</button>
                                                    </>
                                                )}
                                                {req.status === 'PAGADO' && (
                                                    <button onClick={() => handleAction(req.id, 'CONFIRMADO')} className="flex-1 md:flex-none bg-secondary text-white px-6 py-2 rounded-full font-bold hover:bg-secondary-container transition">Confirmar Pago</button>
                                                )}
                                                {req.status !== 'PENDIENTE' && req.status !== 'PAGADO' && (
                                                    <span className={`px-4 py-2 rounded-full text-sm font-bold uppercase ${req.status === 'CONFIRMADO' ? 'bg-green-100 text-green-700' : 'bg-surface-container text-on-surface-variant'}`}>{req.status}</span>
                                                )}
                                            </div>
                                        </div>
                                    </GlassCard>
                                )) : <p className="text-on-surface-variant">No tienes solicitudes pendientes.</p>}
                            </div>
                        </div>
                    )}

                    {activeTab === 'earnings' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Mis Ganancias</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                                <GlassCard className="rounded-[24px] p-8 border-l-4 border-l-primary">
                                    <p className="text-on-surface-variant font-bold mb-2 text-sm uppercase tracking-wider">Balance Acumulado</p>
                                    <p className="font-display-lg text-5xl font-bold text-dark">${earnings.toFixed(2)}</p>
                                    <p className="text-xs text-on-surface-variant mt-2">Corresponde al 90% del total de servicios completados.</p>
                                    <button className="mt-6 bg-primary text-white px-8 py-3 rounded-full font-bold shadow-lg hover:scale-105 transition-all">Retirar Fondos</button>
                                </GlassCard>
                                <GlassCard className="rounded-[24px] p-8 border-l-4 border-l-secondary">
                                    <p className="text-on-surface-variant font-bold mb-2 text-sm uppercase tracking-wider">Servicios Pagados</p>
                                    <p className="font-display-lg text-5xl font-bold text-dark">{requests.filter(r => r.status === 'CONFIRMADO' || r.status === 'COMPLETADO').length}</p>
                                    <p className="text-xs text-on-surface-variant mt-2">Total de servicios confirmados por ti.</p>
                                </GlassCard>
                            </div>
                        </div>
                    )}

                    {activeTab === 'profile' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Editar Mi Perfil</h2>
                            <GlassCard className="rounded-[32px] p-8 shadow-md">
                                <form className="grid grid-cols-1 md:grid-cols-2 gap-6" onSubmit={(e) => {
                                    e.preventDefault();
                                    const form = e.target;
                                    const allUsers = JSON.parse(localStorage.getItem('users') || '[]');
                                    const updatedData = {
                                        full_name: form.full_name.value,
                                        age: form.age.value,
                                        rate: form.rate.value,
                                        experience: form.experience.value,
                                        description: form.description.value,
                                        driverLicense: form.driverLicense.value === 'Sí',
                                        hasCar: form.hasCar.value === 'Sí',
                                        smoker: form.smoker.value === 'Sí',
                                        preferredLocation: form.preferredLocation.value,
                                        education: form.education.value,
                                        superpowers: form.superpowers.value.split(',').map(s => s.trim()),
                                        comfortableWith: form.comfortableWith.value.split(',').map(s => s.trim()),
                                        availability: availability
                                    };
                                    const updatedUsers = allUsers.map(u => u.id === user.id ? { ...u, ...updatedData } : u);
                                    localStorage.setItem('users', JSON.stringify(updatedUsers));
                                    alert('¡Perfil actualizado con éxito!');
                                    window.dispatchEvent(new Event('storage'));
                                }}>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Nombre</label><input type="text" name="full_name" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant focus:ring-2 focus:ring-primary" defaultValue={user?.full_name}/></div>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Edad</label><input type="number" name="age" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant focus:ring-2 focus:ring-primary" defaultValue={user?.age}/></div>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Tarifa ($/hr)</label><input type="number" name="rate" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant focus:ring-2 focus:ring-primary" defaultValue={user?.rate}/></div>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Experiencia (años)</label><input type="number" name="experience" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant focus:ring-2 focus:ring-primary" defaultValue={user?.experience}/></div>

                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2 uppercase text-outline">Descripción</label><textarea name="description" className="w-full p-3 rounded-xl bg-surface-container-low h-20 outline-none border border-outline-variant focus:ring-2 focus:ring-primary" defaultValue={user?.description}></textarea></div>

                                    {/* Availability Table */}
                                    <div className="md:col-span-2">
                                        <label className="block text-xs font-bold mb-2 uppercase text-outline">Disponibilidad Semanal</label>
                                        <div className="overflow-x-auto rounded-2xl border border-outline-variant bg-surface-container-low p-4">
                                            <table className="w-full text-center border-collapse">
                                                <thead>
                                                    <tr>
                                                        <th></th>
                                                        {days.map(d => <th key={d} className="p-2 text-xs font-bold">{d}</th>)}
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {times.map(t => (
                                                        <tr key={t}>
                                                            <td className="p-2 text-[10px] font-bold text-left uppercase text-outline">{timeLabels[t]}</td>
                                                            {days.map(d => (
                                                                <td key={d} className="p-2">
                                                                    <input 
                                                                        type="checkbox" 
                                                                        className="w-5 h-5 rounded border-outline-variant text-primary focus:ring-primary cursor-pointer"
                                                                        checked={availability[d][t]} 
                                                                        onChange={() => toggleAvailability(d, t)}
                                                                    />
                                                                </td>
                                                            ))}
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>

                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Carnet Conducir</label><select name="driverLicense" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant" defaultValue={user?.driverLicense ? 'Sí' : 'No'}><option>Sí</option><option>No</option></select></div>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Coche Propio</label><select name="hasCar" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant" defaultValue={user?.hasCar ? 'Sí' : 'No'}><option>Sí</option><option>No</option></select></div>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Fumador</label><select name="smoker" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant" defaultValue={user?.smoker ? 'Sí' : 'No'}><option>No</option><option>Sí</option></select></div>
                                    <div><label className="block text-xs font-bold mb-2 uppercase text-outline">Lugar Trabajo</label><select name="preferredLocation" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant" defaultValue={user?.preferredLocation}><option>En casa de la familia</option><option>En mi casa</option></select></div>

                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2 uppercase text-outline">Educación</label><textarea name="education" className="w-full p-3 rounded-xl bg-surface-container-low h-16 outline-none border border-outline-variant" defaultValue={user?.education}></textarea></div>
                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2 uppercase text-outline">Superpoderes (comas)</label><input type="text" name="superpowers" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant" defaultValue={user?.superpowers?.join(', ')}/></div>
                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2 uppercase text-outline">Cómoda con (comas)</label><input type="text" name="comfortableWith" className="w-full p-3 rounded-xl bg-surface-container-low outline-none border border-outline-variant" defaultValue={user?.comfortableWith?.join(', ')}/></div>

                                    <button type="submit" className="md:col-span-2 bg-primary text-white px-8 py-4 rounded-full font-bold shadow-lg hover:bg-primary-container transition mt-4 active:scale-95">Guardar Cambios del Perfil</button>
                                </form>
                            </GlassCard>
                        </div>
                    )}
                </main>
            </div>
        </div>
    );
};

export default SitterDashboard;
